func DecodeBuildConfig(m any) (BuildConfig, error) {
	b := DefaultBuildConfig
	if m == nil {
		return b, nil
	}

	err := mapstructure.WeakDecode(m, &b)

	switch b.List {
	case "0":
		b.List = Never
	case "1":
		b.List = Always
	case Always, Never, ListLocally:
	default:
		b.List = Always
	}

	switch b.Render {
	case "0":
		b.Render = Never
	case "1":
		b.Render = Always
	case Always, Never, Link:
	default:
		b.Render = Always
	}

	return b, err
}
